<body>
<textarea id="yh-raw-message" style="display:none">$1</textarea>
<div id="yh-loader" style="padding:12px;border:1px solid #8c6a2c;border-radius:8px;color:#f0d995;background:#14100b;line-height:1.6;font-family:Microsoft YaHei, sans-serif">云海神豪前端加载中……</div>
<script>
(async () => {
  const url = 'https://raw.githubusercontent.com/Baichen-xi/SillyTavern-storehouse/main/yunhai-shenhao/v1/index.html?v=20260516-10';
  const loader = document.getElementById('yh-loader');
  try {
    const response = await fetch(url, { cache: 'no-store' });
    if (!response.ok) throw new Error('HTTP ' + response.status);
    const html = await response.text();
    loader.innerHTML = html;
    loader.querySelectorAll('script').forEach(oldScript => {
      const script = document.createElement('script');
      for (const attr of oldScript.attributes) script.setAttribute(attr.name, attr.value);
      script.textContent = oldScript.textContent;
      oldScript.replaceWith(script);
    });
  } catch (error) {
    const raw = document.getElementById('yh-raw-message').value || '';
    loader.innerHTML = '<b>云海神豪前端加载失败</b><br><small>' + String(error && error.message || error) + '</small><details style="margin-top:8px"><summary>显示文本模式备份</summary><pre style="white-space:pre-wrap;color:#f7f1df">' + raw.replace(/[<>&]/g, s => ({"<":"&lt;", ">":"&gt;", "&":"&amp;"}[s])) + '</pre></details>';
  }
})();
</script>
</body>
